<header class="h-16 border-b border-slate-200 bg-white px-8 flex items-center justify-between shrink-0 shadow-sm"><h1 class="text-xl font-bold text-slate-800 tracking-tight">{{ $title ?? 'WorkLivePro' }}</h1><div class="flex items-center space-x-6"><div class="hidden sm:flex items-center space-x-2 text-slate-500 text-xs font-medium font-mono bg-slate-50 border border-slate-200 py-1.5 px-3.5 rounded-lg" title="Zona horaria corporativa: {{ $corporateTimezone }}"><span>◷</span><span>{{ $corporateNow->locale('es')->isoFormat('D MMM YYYY') }}</span><span class="text-slate-300">|</span><span class="text-slate-750 font-bold" id="live-clock">{{ $corporateNow->format('H:i:s') }}</span></div><span class="flex items-center gap-1.5 px-2.5 py-0.5 rounded-full bg-emerald-50 text-emerald-600 text-xs font-semibold uppercase tracking-wider border border-emerald-100"><span class="w-2 h-2 rounded-full bg-emerald-500"></span> Sincronizado Live</span></div></header><script>const workLiveTimezone=@json($corporateTimezone ?? 'America/Mexico_City');const updateLiveClock=()=>{const e=document.getElementById('live-clock');if(e)e.textContent=new Intl.DateTimeFormat('es-MX',{timeZone:workLiveTimezone,hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false}).format(new Date())};setInterval(updateLiveClock,1000)</script>
